Add a new `SwitchSettingRow` component as an additional named export in `apps/client/src/layers/shared/ui/setting-row.tsx`. Do NOT change the existing `SettingRow` export — append the new component below it.

Full implementation (copy verbatim, but reuse the existing `SettingRow` import — no need for a new import):

```tsx
import { Switch } from './switch';

interface SwitchSettingRowProps {
  /** Label text. */
  label: string;
  /** Description text below the label. */
  description: string;
  /** Switch checked state. */
  checked: boolean;
  /** Switch onCheckedChange handler. */
  onCheckedChange: (checked: boolean) => void;
  /** Optional aria-label override. Defaults to the label. */
  ariaLabel?: string;
  /** Optional className for the row. */
  className?: string;
  /** Optional disabled state. */
  disabled?: boolean;
}

/**
 * Switch + label row shorthand — the most common settings pattern.
 *
 * Wraps a `Switch` inside a `SettingRow` with consistent `aria-label`
 * defaulting and disabled state forwarding.
 */
export function SwitchSettingRow({
  label,
  description,
  checked,
  onCheckedChange,
  ariaLabel,
  className,
  disabled,
}: SwitchSettingRowProps) {
  return (
    <SettingRow label={label} description={description} className={className}>
      <Switch
        checked={checked}
        onCheckedChange={onCheckedChange}
        aria-label={ariaLabel ?? label}
        disabled={disabled}
      />
    </SettingRow>
  );
}

export type { SwitchSettingRowProps };
```

Note: in the existing file, `SettingRow` is in scope so the only new import needed is `Switch` from `./switch`.

